from flask import Flask, render_template_string, jsonify
import os, sys

app = Flask(__name__)
counter = 0

NG_LOGO = "data:image/png;base64,"

@app.route("/api/increment", methods=["POST"])
def increment():
    global counter
    counter += 1
    return jsonify({"count": counter})

@app.route("/api/status")
def api_status():
    return jsonify({"status": "online", "python_version": sys.version.split()[0], "environment": os.environ.get("ENVIRONMENT", "dev"), "count": counter})

HTML_TEMPLATE = """
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>CIDO Workshop Starter</title>
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;600;700;800&display=swap" rel="stylesheet">
    <style>
        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
        body { font-family: "Inter", Arial, sans-serif; background: #ffffff; color: #1a1a1a; min-height: 100vh; display: flex; flex-direction: column; }
        .topbar { display: flex; justify-content: flex-end; align-items: center; padding: 1.25rem 2.5rem; border-bottom: 1px solid #e8eaf0; }
        .ng-logo { height: 52px; width: auto; display: block; }
        .main { flex: 1; display: flex; align-items: center; padding: 4rem 6rem; gap: 5rem; }
        .hero-block { background: #0A31A1; border-radius: 10px; padding: 3rem 3.5rem 3rem 3rem; min-width: 380px; max-width: 440px; flex-shrink: 0; }
        .hero-block h1 { font-size: 2.1rem; font-weight: 800; color: #ffffff; line-height: 1.25; margin-bottom: 1.1rem; }
        .hero-divider { width: 48px; height: 5px; background: #ffffff; border-radius: 3px; margin-bottom: 1.1rem; }
        .hero-sub { font-size: 1.1rem; font-weight: 600; color: #ffffff; }
        .interaction-area { flex: 1; display: flex; flex-direction: column; justify-content: center; gap: 1.5rem; }
        .action-row { display: flex; align-items: center; gap: 1.5rem; }
        .trigger-btn { background: #0A31A1; color: #ffffff; border: none; border-radius: 8px; padding: 0.85rem 2rem; font-size: 1.05rem; font-weight: 600; font-family: "Inter", Arial, sans-serif; cursor: pointer; transition: background 0.18s ease, transform 0.1s ease; white-space: nowrap; }
        .trigger-btn:hover { background: #082888; }
        .trigger-btn:active { transform: scale(0.97); background: #061f73; }
        .action-label { font-size: 1.2rem; font-weight: 700; color: #1a1a1a; white-space: nowrap; }
        .action-count { color: #0A31A1; }
        .env-badge { display: inline-block; font-size: 0.72rem; font-weight: 700; text-transform: uppercase; letter-spacing: 1.5px; padding: 0.3rem 0.75rem; border-radius: 6px; background: #eef1fb; color: #0A31A1; border: 1px solid #c5cef0; }
        footer { border-top: 1px solid #e8eaf0; padding: 1.25rem; text-align: center; font-size: 0.88rem; color: #9ca3af; }
        footer strong { font-weight: 600; color: #6b7280; }
    </style>
</head>
<body>
    <header class="topbar">
        <img class="ng-logo" src="{{ logo }}" alt="Northrop Grumman">
    </header>
    <main class="main">
        <div class="hero-block">
            <h1>Chief Information &amp; Digital Office Workshop Starter</h1>
            <div class="hero-divider"></div>
            <p class="hero-sub">Presented by the EKHO Team</p>
        </div>
        <div class="interaction-area">
            <div><span class="env-badge">{{ env_label }}</span></div>
            <div class="action-row">
                <button class="trigger-btn" onclick="triggerAction()">Trigger Action</button>
                <span class="action-label">Action Recorded: <span class="action-count" id="count-display">0</span></span>
            </div>
        </div>
    </main>
    <footer>Powered by <strong>Python Flask</strong></footer>
    <script>
        async function triggerAction() {
            try {
                const resp = await fetch("/api/increment", { method: "POST" });
                const data = await resp.json();
                document.getElementById("count-display").innerText = data.count;
            } catch (e) { console.error("Error:", e); }
        }
    </script>
</body>
</html>
"""

@app.route("/")
def home():
    env = os.environ.get("ENVIRONMENT", "dev")
    env_label = "Production" if env == "prod" else "Development"
    return render_template_string(HTML_TEMPLATE, logo=NG_LOGO, env_label=env_label)

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=8080)
